#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

long long gcd(long long a, long long b) {
    while (b) {
        a %= b;
        std::swap(a, b);
    }
    return a;
}

long long solve(std::vector<long long> nums, long long p, std::vector<std::vector<long long>> queries) {
    int n = nums.size();
    int q = queries.size();
    long long good_subsequence_count = 0;

    // Helper function to check for the existence of a "good subsequence"
    auto check_good_subsequence = [&](const std::vector<long long>& current_nums) -> bool {
        // A good subsequence must have length < n and GCD = p.

        // Condition 1: All elements must be multiples of p, otherwise the GCD cannot be p.
        // If any element is not divisible by p, no subset containing it can have GCD = p.
        // If we only consider elements divisible by p, their GCD will be a multiple of p.

        std::vector<long long> multiples_of_p;
        for (long long x : current_nums) {
            if (x % p == 0) {
                multiples_of_p.push_back(x);
            }
        }

        if (multiples_of_p.empty()) {
            return false;
        }

        // The problem is equivalent to: can we find a non-empty subsequence 
        // of multiples_of_p (of length < n) whose GCD is exactly p?

        // Since we are looking for *any* good subsequence, we check the following:

        // Case 1: Check for a subsequence of length 1.
        // A subsequence of length 1, [x], has GCD = x. For it to be good:
        // 1. Length < n (i.e., 1 < n). This is true since n >= 2.
        // 2. GCD = p (i.e., x = p).
        for (long long x : current_nums) {
            if (x == p && n > 1) {
                return true;
            }
        }

        // Case 2: Check for subsequences of length >= 2.
        // If there are at least two elements divisible by p, we check if their GCD can be p.
        if (multiples_of_p.size() < 2) {
            return false;
        }

        // The maximum possible GCD among all subsequences is the GCD of all elements 
        // divisible by p. If this GCD is exactly p, then a subsequence exists (e.g., the full set of multiples).
        // However, we must also ensure the length is < n.

        // Let S be the set of indices i such that nums[i] is divisible by p.
        // We need to find a subset I subset S such that |I| < n and GCD({nums[i] | i in I}) = p.

        // If |S| < n, then the subsequence formed by all elements in S is a candidate, 
        // and its length is less than n.
        if (multiples_of_p.size() < n) {
            long long current_gcd = multiples_of_p[0];
            for (size_t i = 1; i < multiples_of_p.size(); ++i) {
                current_gcd = gcd(current_gcd, multiples_of_p[i]);
            }
            if (current_gcd == p) {
                return true;
            }
        }

        // If |S| = n (i.e., all elements are divisible by p), then any subsequence of length < n 
        // is allowed. The GCD of all n elements is g. If g > p, no subsequence GCD can be p 
        // (since all elements are multiples of p, their GCD must be a multiple of p).
        // If g = p, the entire set is not good (length = n), but since n >= 2, 
        // we can always remove one element x_i. The GCD of the remaining n-1 elements 
        // must be a multiple of p, and it must be <= g = p. Thus, the GCD must be exactly p.
        if (multiples_of_p.size() == n) {
             long long current_gcd = multiples_of_p[0];
            for (size_t i = 1; i < multiples_of_p.size(); ++i) {
                current_gcd = gcd(current_gcd, multiples_of_p[i]);
            }
            if (current_gcd == p) {
                // Since n >= 2, we can form a subsequence of length n-1, whose GCD must be p.
                // If GCD(all) = p, removing any element x_i results in GCD(rest) being a multiple of p, 
                // and GCD(rest) must divide p (since p divides all elements). Thus GCD(rest) = p.
                return true;
            }
        }

        // A more robust check for GCD=p when all elements are multiples of p:
        // If the GCD of ALL elements divisible by p is G.
        // If G = p, and the count of such elements is >= 2, then a good subsequence exists:
        // If count < n, use all of them.
        // If count = n, remove one element, GCD remains p.
        if (multiples_of_p.size() >= 2) {
            long long current_gcd = multiples_of_p[0];
            for (size_t i = 1; i < multiples_of_p.size(); ++i) {
                current_gcd = gcd(current_gcd, multiples_of_p[i]);
            }
            if (current_gcd == p) {
                 // Length condition check:
                 if (multiples_of_p.size() < n) {
                     return true;
                 } else { // size == n
                     // Since n >= 2, we can always take n-1 elements.
                     return true;
                 }
            }
        }

        return false;
    };

    for (int i = 0; i < q; ++i) {
        std::vector<long long> query = queries[i];
        int index = query[0];
        long long value = query[1];

        // Update nums
        nums[index] = value;

        // Check the condition
        if (check_good_subsequence(nums)) {
            good_subsequence_count++;
        }
    }

    return good_subsequence_count;
}
